  ('retired-7c9828ae-moex-00187', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '依我國現行法規定，下列何者非屬公法人？ 直轄市山地原住民區   國家運動訓練中心 國家圖書館    國家表演藝術中心', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00188', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '屏東縣政府將原住民慶典活動委由該縣牡丹鄉辦理，此種情形屬於下列何者？ 權限委任  權限委託  委辦  職務協助', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00189', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '依據現行有關規定及實務見解，關於公務人員之考績權之敘述，下列何者錯誤？ 公務人員年終考績被列為丙等者，由於未改變其身分不得提起行政訴訟 公務人員年終考績被列為丙等者，將影響其陞任之權利 公務人員年終考績被列為丙等者，將影響其參加升官等訓練之權益 公務人員之考績評定，學理上認為是高度屬人性判斷之事項', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00190', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '關於公務員懲戒法制之敘述，下列何者正確？ 行政院部會首長認為其所屬薦任第十職等之公務員有違法執行職務情事，得將該公務員逕送懲 戒法院審理 公務員懲戒處分之種類包括停職 經監察院移送懲戒法院審理中之公務員，於懲戒法院審理確定前，仍得申請退休 公務員因懲戒法庭裁定停止其職務，其於停職期間所為之職務行為，不生效力', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00191', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '下列何種人事行政措施，可依公務人員保障法規定提起申訴及再申訴？ 他機關借調本機關現職人員，占他機關職缺工作 本機關現職人員申請兼任他機關職務遭否准 停職人員申請復職遭否准 服務機關更動公務人員工作項目', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00192', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '有關行政命令之敘述，下列何者錯誤？ 行政程序法規定行政命令之分類，為授權命令與職權命令 授權命令即學理上所稱之委任命令 法規命令發布後應即送立法機關 行政機關訂定解釋性之行政規則，應由其首長簽署，並登載於政府公報發布之', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00193', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '關於法律保留原則之敘述，下列何者錯誤？ 國會保留事項係指不得以行政命令規定之事項 行政機關得以行政規則剝奪人民之自由、權利 法律授權之法規命令，得規定細節性、技術性之事項 應以法律規定之事項，不得以命令定之 13730', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00194', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '機關年度派遣人力勞務採購，以最低價招標公告後，甲、乙、丙三人投標，最後由丙最低價得標， 該決標性質與效力，下列敘述何者正確？ 決標為私經濟契約行為 決標為具第三人效力之行政處分 決標後採購契約即為成立生效，無須簽約 甲發現丙投標文件造假，應向民事法院提起訴訟', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00195', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '市政府徵收私有土地整治河川，擬告知權利人領取補償金，下列何者非屬合法通知之方式？ 市政府只張貼函文在主管機關公布欄 市政府以掛號郵寄函文至本人住居所 郵寄送達函文由本人同居配偶簽收 郵寄送達處所2次無人應答時，將函文寄存郵政機構，黏貼通知書於門首，並將另一通知書投 入送達處所信箱', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00196', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '下列何者為無效之行政處分？ 行政處分所依據之法規命令違反法律保留原則 交通違規事件之裁罰單上記載之違規日期為民國200年1月1日 行政處分之作成未依法定程序 未記明處分理由', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL)
